#!/usr/bin/env node

const fs = require('fs');
const path = require('path');

// Parse command line arguments
const [,, inputPath, outputPath] = process.argv;

if (!inputPath || !outputPath) {
  console.error('Usage: node ua-arch-analyze.js <input.json> <output.json>');
  process.exit(1);
}

try {
  // Read input
  const inputData = JSON.parse(fs.readFileSync(inputPath, 'utf8'));
  const { fileNodes, importEdges, allEdges } = inputData;

  // Initialize results
  const results = {
    scriptCompleted: true,
    directoryGroups: {},
    nodeTypeGroups: {},
    crossCategoryEdges: [],
    interGroupImports: [],
    intraGroupDensity: {},
    patternMatches: {},
    deploymentTopology: {
      hasDockerfile: false,
      hasCompose: false,
      hasK8s: false,
      hasTerraform: false,
      hasCI: false,
      infraFiles: []
    },
    dataPipeline: {
      schemaFiles: [],
      migrationFiles: [],
      dataModelFiles: [],
      apiHandlerFiles: []
    },
    docCoverage: {
      groupsWithDocs: 0,
      totalGroups: 0,
      coverageRatio: 0,
      undocumentedGroups: []
    },
    dependencyDirection: [],
    fileStats: {
      totalFileNodes: fileNodes.length,
      filesPerGroup: {},
      nodeTypeCounts: {}
    },
    fileFanIn: {},
    fileFanOut: {}
  };

  // A. Directory Grouping - find common prefix and group by first directory after prefix
  const allPaths = fileNodes.map(n => n.filePath);

  // Find common prefix
  let commonPrefix = '';
  if (allPaths.length > 0) {
    const sortedPaths = allPaths.slice().sort();
    const first = sortedPaths[0];
    const last = sortedPaths[sortedPaths.length - 1];

    for (let i = 0; i < first.length; i++) {
      if (first[i] === last[i]) {
        commonPrefix += first[i];
      } else {
        break;
      }
    }

    // Trim to last directory separator
    const lastSlash = commonPrefix.lastIndexOf('/');
    if (lastSlash > 0) {
      commonPrefix = commonPrefix.substring(0, lastSlash + 1);
    } else {
      commonPrefix = '';
    }
  }

  // Group files by directory after common prefix
  fileNodes.forEach(node => {
    let filePath = node.filePath;

    // Remove common prefix
    if (commonPrefix && filePath.startsWith(commonPrefix)) {
      filePath = filePath.substring(commonPrefix.length);
    }

    // Get first directory segment
    let groupName;
    const parts = filePath.split('/');

    if (parts.length === 1) {
      // File in root
      groupName = 'root';
    } else {
      groupName = parts[0];
    }

    if (!results.directoryGroups[groupName]) {
      results.directoryGroups[groupName] = [];
    }
    results.directoryGroups[groupName].push(node.id);
  });

  // B. Node Type Grouping
  fileNodes.forEach(node => {
    const nodeType = node.type || 'file';
    if (!results.nodeTypeGroups[nodeType]) {
      results.nodeTypeGroups[nodeType] = [];
    }
    results.nodeTypeGroups[nodeType].push(node.id);

    // Count node types
    results.fileStats.nodeTypeCounts[nodeType] =
      (results.fileStats.nodeTypeCounts[nodeType] || 0) + 1;
  });

  // Count files per group
  for (const [groupName, nodeIds] of Object.entries(results.directoryGroups)) {
    results.fileStats.filesPerGroup[groupName] = nodeIds.length;
  }

  // C. Import Adjacency Matrix
  const importsBySource = {};
  const importsByTarget = {};

  importEdges.forEach(edge => {
    if (!importsBySource[edge.source]) {
      importsBySource[edge.source] = [];
    }
    importsBySource[edge.source].push(edge.target);

    if (!importsByTarget[edge.target]) {
      importsByTarget[edge.target] = [];
    }
    importsByTarget[edge.target].push(edge.source);
  });

  // Calculate fan-in and fan-out
  fileNodes.forEach(node => {
    const fanOut = importsBySource[node.id]?.length || 0;
    const fanIn = importsByTarget[node.id]?.length || 0;

    if (fanIn > 0) {
      results.fileFanIn[node.id] = fanIn;
    }
    if (fanOut > 0) {
      results.fileFanOut[node.id] = fanOut;
    }
  });

  // D. Cross-Category Dependency Analysis
  const crossCategoryMap = {};

  allEdges.forEach(edge => {
    const sourceNode = fileNodes.find(n => n.id === edge.source);
    const targetNode = fileNodes.find(n => n.id === edge.target);

    if (sourceNode && targetNode) {
      const key = `${sourceNode.type}->${targetNode.type}-${edge.type}`;
      crossCategoryMap[key] = (crossCategoryMap[key] || 0) + 1;
    }
  });

  results.crossCategoryEdges = Object.entries(crossCategoryMap).map(([key, count]) => {
    const [fromTo, edgeType] = key.split('-' + key.split('-').pop());
    const [fromType, toType] = fromTo.split('->');
    return { fromType, toType, edgeType, count };
  });

  // E. Inter-Group Import Frequency
  const interGroupMap = {};

  importEdges.forEach(edge => {
    const sourceNode = fileNodes.find(n => n.id === edge.source);
    const targetNode = fileNodes.find(n => n.id === edge.target);

    if (sourceNode && targetNode) {
      const sourceGroup = findGroupForNode(sourceNode.id, results.directoryGroups);
      const targetGroup = findGroupForNode(targetNode.id, results.directoryGroups);

      if (sourceGroup && targetGroup && sourceGroup !== targetGroup) {
        const key = `${sourceGroup}->${targetGroup}`;
        interGroupMap[key] = (interGroupMap[key] || 0) + 1;
      }
    }
  });

  results.interGroupImports = Object.entries(interGroupMap).map(([key, count]) => {
    const [from, to] = key.split('->');
    return { from, to, count };
  });

  // F. Intra-Group Import Density
  for (const [groupName, nodeIds] of Object.entries(results.directoryGroups)) {
    let internalEdges = 0;
    let totalEdges = 0;

    importEdges.forEach(edge => {
      const sourceInGroup = nodeIds.includes(edge.source);
      const targetInGroup = nodeIds.includes(edge.target);

      if (sourceInGroup || targetInGroup) {
        totalEdges++;
        if (sourceInGroup && targetInGroup) {
          internalEdges++;
        }
      }
    });

    results.intraGroupDensity[groupName] = {
      internalEdges,
      totalEdges,
      density: totalEdges > 0 ? internalEdges / totalEdges : 0
    };
  }

  // G. Directory Pattern Matching
  const patternMap = {
    'routes': 'api', 'api': 'api', 'controllers': 'api', 'endpoints': 'api', 'handlers': 'api',
    'services': 'service', 'core': 'service', 'lib': 'service', 'domain': 'service', 'logic': 'service',
    'models': 'data', 'db': 'data', 'data': 'data', 'persistence': 'data', 'repository': 'data', 'entities': 'data',
    'components': 'ui', 'views': 'ui', 'pages': 'ui', 'ui': 'ui', 'layouts': 'ui', 'screens': 'ui',
    'middleware': 'middleware', 'plugins': 'middleware', 'interceptors': 'middleware', 'guards': 'middleware',
    'utils': 'utility', 'helpers': 'utility', 'common': 'utility', 'shared': 'utility', 'tools': 'utility',
    'config': 'config', 'constants': 'config', 'env': 'config', 'settings': 'config',
    '__tests__': 'test', 'test': 'test', 'tests': 'test', 'spec': 'test', 'specs': 'test',
    'types': 'types', 'interfaces': 'types', 'schemas': 'types', 'contracts': 'types', 'dtos': 'types',
    'hooks': 'hooks',
    'store': 'state', 'state': 'state', 'reducers': 'state', 'actions': 'state', 'slices': 'state',
    'assets': 'assets', 'static': 'assets', 'public': 'assets', 'res': 'assets',
    'migrations': 'data',
    'management': 'config', 'commands': 'config',
    'templatetags': 'utility',
    'signals': 'service',
    'serializers': 'api',
    'cmd': 'entry',
    'internal': 'service',
    'pkg': 'utility',
    'dto': 'types', 'request': 'types', 'response': 'types',
    'entity': 'data',
    'controller': 'api',
    'routers': 'api',
    'composables': 'service',
    'blueprints': 'api',
    'mailers': 'service', 'jobs': 'service', 'channels': 'service',
    'bin': 'entry',
    'docs': 'documentation', 'documentation': 'documentation', 'wiki': 'documentation',
    'deploy': 'infrastructure', 'deployment': 'infrastructure', 'infra': 'infrastructure', 'infrastructure': 'infrastructure',
    '.github': 'ci-cd', '.gitlab': 'ci-cd', '.circleci': 'ci-cd',
    'k8s': 'infrastructure', 'kubernetes': 'infrastructure', 'helm': 'infrastructure', 'charts': 'infrastructure',
    'terraform': 'infrastructure', 'tf': 'infrastructure',
    'docker': 'infrastructure',
    'sql': 'data', 'database': 'data', 'schema': 'data',
    'script': 'script', 'scripts': 'script',
    'gradle': 'config',
    'app': 'application',
    'opencore': 'sdk',
    'eajni': 'jni',
    'cpp': 'native'
  };

  for (const [groupName] of Object.entries(results.directoryGroups)) {
    const lowerName = groupName.toLowerCase();
    if (patternMap[lowerName]) {
      results.patternMatches[groupName] = patternMap[lowerName];
    }
  }

  // H. Deployment Topology Detection
  fileNodes.forEach(node => {
    const fileName = node.name.toLowerCase();
    const filePath = node.filePath.toLowerCase();

    if (fileName === 'dockerfile' || fileName.startsWith('dockerfile.')) {
      results.deploymentTopology.hasDockerfile = true;
      results.deploymentTopology.infraFiles.push(node.filePath);
    }
    if (fileName.startsWith('docker-compose')) {
      results.deploymentTopology.hasCompose = true;
      results.deploymentTopology.infraFiles.push(node.filePath);
    }
    if (filePath.includes('k8s/') || filePath.includes('kubernetes/')) {
      results.deploymentTopology.hasK8s = true;
      results.deploymentTopology.infraFiles.push(node.filePath);
    }
    if (fileName.endsWith('.tf') || fileName.endsWith('.tfvars')) {
      results.deploymentTopology.hasTerraform = true;
      results.deploymentTopology.infraFiles.push(node.filePath);
    }
    if (filePath.includes('.github/workflows') || fileName === '.gitlab-ci.yml' ||
        fileName === 'jenkinsfile' || fileName === 'jitpack.yml') {
      results.deploymentTopology.hasCI = true;
      results.deploymentTopology.infraFiles.push(node.filePath);
    }
  });

  // I. Data Pipeline Detection
  fileNodes.forEach(node => {
    const fileName = node.name.toLowerCase();
    const filePath = node.filePath.toLowerCase();

    if (fileName.endsWith('.sql') || fileName.endsWith('.graphql') || fileName.endsWith('.proto')) {
      results.dataPipeline.schemaFiles.push(node.filePath);
    }
    if (filePath.includes('migration')) {
      results.dataPipeline.migrationFiles.push(node.filePath);
    }
    if (filePath.includes('model') || filePath.includes('entity')) {
      results.dataPipeline.dataModelFiles.push(node.filePath);
    }
    if (filePath.includes('route') || filePath.includes('controller') || filePath.includes('handler')) {
      results.dataPipeline.apiHandlerFiles.push(node.filePath);
    }
  });

  // J. Documentation Coverage
  const groupsWithDocs = new Set();

  fileNodes.forEach(node => {
    if (node.type === 'document' || node.filePath.toLowerCase().includes('readme')) {
      const group = findGroupForNode(node.id, results.directoryGroups);
      if (group) {
        groupsWithDocs.add(group);
      }
    }
  });

  results.docCoverage.groupsWithDocs = groupsWithDocs.size;
  results.docCoverage.totalGroups = Object.keys(results.directoryGroups).length;
  results.docCoverage.coverageRatio = results.docCoverage.totalGroups > 0
    ? groupsWithDocs.size / results.docCoverage.totalGroups
    : 0;

  results.docCoverage.undocumentedGroups = Object.keys(results.directoryGroups)
    .filter(g => !groupsWithDocs.has(g));

  // K. Dependency Direction
  const dependencyCountMap = {};

  results.interGroupImports.forEach(({ from, to, count }) => {
    const key = [from, to].sort().join('<->');
    if (!dependencyCountMap[key]) {
      dependencyCountMap[key] = { group1: from, group2: to, count1: 0, count2: 0 };
    }
    if (from < to) {
      dependencyCountMap[key].count1 += count;
    } else {
      dependencyCountMap[key].count2 += count;
    }
  });

  Object.values(dependencyCountMap).forEach(({ group1, group2, count1, count2 }) => {
    if (count1 > count2) {
      results.dependencyDirection.push({ dependent: group1, dependsOn: group2 });
    } else if (count2 > count1) {
      results.dependencyDirection.push({ dependent: group2, dependsOn: group1 });
    }
  });

  // Write output
  fs.writeFileSync(outputPath, JSON.stringify(results, null, 2));
  process.exit(0);

} catch (error) {
  console.error('Error:', error.message);
  console.error(error.stack);
  process.exit(1);
}

function findGroupForNode(nodeId, directoryGroups) {
  for (const [groupName, nodeIds] of Object.entries(directoryGroups)) {
    if (nodeIds.includes(nodeId)) {
      return groupName;
    }
  }
  return null;
}
